package rlp

import (
	"encoding/binary"
	"errors"
	"fmt"
	"math/bits"
	// Consider importing "io" if you prefer io.ErrUnexpectedEOF over ErrInsufficientData
)

var (
	// ErrInvalidRLPData indicates malformed or unexpected RLP data.
	ErrInvalidRLPData = errors.New("rlp: invalid RLP data")
	// ErrInsufficientData means the input byte slice was too short for the declared RLP structure.
	ErrInsufficientData = errors.New("rlp: insufficient data for decoding")
	// ErrNonCanonicalRLP signifies that the RLP data was not encoded in its shortest, canonical form.
	ErrNonCanonicalRLP = errors.New("rlp: non-canonical encoding")
	// ErrRLPIntegerTooLarge indicates that a length prefix decodes to a value larger than uint64 supports
	// or implies a data size exceeding reasonable limits (e.g., max int).
	ErrRLPIntegerTooLarge = errors.New("rlp: integer represented by RLP data exceeds supported size")
)

// DecodeRLP decodes the first RLP item from the input byte slice.
// It returns the decoded item (either []byte for strings or []any for lists),
// the number of bytes consumed from the input data, and an error if decoding fails.
// It performs canonical checks: ensures shortest form is used and lengths are minimally encoded.
func DecodeRLP(data []byte) (item any, consumed int, err error) {
	dataLen := len(data)
	if dataLen == 0 {
		err = ErrInsufficientData
		return
	}

	prefix := data[0]

	switch {
	// Case 1: Single byte (0x00 - 0x7f)
	case prefix <= stringShortCutoff: // 0x7f
		// Item is the byte itself, returned as a single-byte slice.
		consumed = 1
		item = []byte{prefix}
		return

	// Case 2: Short string (0x80 - 0xb7)
	case prefix <= stringLongPrefix: // 0xb7
		length := int(prefix - stringShortPrefix) // length = prefix - 0x80
		consumed = 1 + length

		// Bounds check
		if dataLen < consumed {
			err = ErrInsufficientData
			return
		}
		// Canonical check: single byte 0x00-0x7f must not be encoded as 0x81, byte
		if length == 1 && data[1] <= stringShortCutoff {
			err = fmt.Errorf("%w: single byte string used for value <= 0x7f", ErrNonCanonicalRLP)
			return
		}

		item = data[1:consumed]
		return

	// Case 3: Long string (0xb8 - 0xbf)
	case prefix <= listShortPrefix-1: // 0xbf (upper bound for strings)
		lenOfLength := int(prefix - stringLongPrefix) // lenOfLength = prefix - 0xb7
		lengthStart := 1
		lengthEnd := lengthStart + lenOfLength

		// Bounds check for length bytes
		if dataLen < lengthEnd {
			err = ErrInsufficientData
			return
		}

		// Decode the actual length
		var actualLength uint64
		actualLength, err = bytesToUint64(data[lengthStart:lengthEnd])
		if err != nil {
			// Add context to canonical/size errors from length decoding
			if errors.Is(err, ErrNonCanonicalRLP) || errors.Is(err, ErrRLPIntegerTooLarge) {
				err = fmt.Errorf("decoding long string length: %w", err)
			} else {
				err = fmt.Errorf("%w: invalid long string length bytes", ErrInvalidRLPData)
			}
			return
		}

		// Canonical check: length must be >= 56 (otherwise short form should be used)
		if actualLength <= uint64(stringMedCutoff) { // 55
			err = fmt.Errorf("%w: long string used for length <= 55", ErrNonCanonicalRLP)
			return
		}

		// Calculate total consumed bytes and perform final bounds check
		// Use uint64 for intermediate calculation to prevent overflow before check
		dataStart := uint64(lengthEnd)
		totalConsumed64 := dataStart + actualLength

		// Check if the total size exceeds limits (uint64 max or practical int max)
		maxInt := uint64(^uint(0) >> 1) // Max value for int on this architecture
		if totalConsumed64 > maxInt {
			err = fmt.Errorf("%w: decoded string size (%d) exceeds system limits", ErrRLPIntegerTooLarge, totalConsumed64)
			return
		}
		consumed = int(totalConsumed64)

		if uint64(dataLen) < totalConsumed64 {
			err = ErrInsufficientData
			return
		}

		item = data[dataStart:consumed]
		return

	// Case 4: Short list (0xc0 - 0xf7)
	case prefix <= listLongPrefix: // 0xf7
		payloadLength := int(prefix - listShortPrefix) // payloadLength = prefix - 0xc0
		payloadStart := 1
		consumed = payloadStart + payloadLength

		// Bounds check for the entire list structure
		if dataLen < consumed {
			err = ErrInsufficientData
			return
		}

		// Decode payload items recursively
		item, err = decodeListPayload(data[payloadStart:consumed])
		if err != nil {
			// Add context if list payload decoding failed
			err = fmt.Errorf("decoding short list: %w", err)
		}
		return

	// Case 5: Long list (0xf8 - 0xff)
	default:
		lenOfLength := int(prefix - listLongPrefix) // lenOfLength = prefix - 0xf7
		lengthStart := 1
		lengthEnd := lengthStart + lenOfLength

		// Bounds check for length bytes
		if dataLen < lengthEnd {
			err = ErrInsufficientData
			return
		}

		// Decode the actual payload length
		var payloadLength uint64
		payloadLength, err = bytesToUint64(data[lengthStart:lengthEnd])
		if err != nil {
			if errors.Is(err, ErrNonCanonicalRLP) || errors.Is(err, ErrRLPIntegerTooLarge) {
				err = fmt.Errorf("decoding long list length: %w", err)
			} else {
				err = fmt.Errorf("%w: invalid long list length bytes", ErrInvalidRLPData)
			}
			return
		}

		// Canonical check: payload length must be >= 56
		if payloadLength <= uint64(listShortCutoff) { // 55
			err = fmt.Errorf("%w: long list used for payload length <= 55", ErrNonCanonicalRLP)
			return
		}

		// Calculate total consumed bytes and final bounds check
		payloadStart64 := uint64(lengthEnd)
		totalConsumed64 := payloadStart64 + payloadLength
		maxInt := uint64(^uint(0) >> 1)
		if totalConsumed64 > maxInt {
			err = fmt.Errorf("%w: decoded list size (%d) exceeds system limits", ErrRLPIntegerTooLarge, totalConsumed64)
			return
		}
		consumed = int(totalConsumed64)

		if uint64(dataLen) < totalConsumed64 {
			err = ErrInsufficientData
			return
		}

		// Decode payload items recursively
		item, err = decodeListPayload(data[int(payloadStart64):consumed])
		if err != nil {
			// Add context if list payload decoding failed
			err = fmt.Errorf("decoding long list: %w", err)
		}
		return
	}
}

// decodeListPayload recursively decodes items from a list's payload data.
func decodeListPayload(payload []byte) ([]any, error) {
	items := []any{}
	payloadLen := len(payload)
	processed := 0
	for processed < payloadLen {
		// Recursively decode the next item in the payload
		subItem, subConsumed, err := DecodeRLP(payload[processed:])
		if err != nil {
			// Add context to the error, indicating which item failed
			return nil, fmt.Errorf("item %d in list payload: %w", len(items), err)
		}

		// Basic sanity check: consumed bytes must be positive
		if subConsumed <= 0 {
			return nil, fmt.Errorf("%w: decoder consumed non-positive bytes (%d) for item %d", ErrInvalidRLPData, subConsumed, len(items))
		}

		items = append(items, subItem)
		processed += subConsumed
	}

	// Check if the sum of consumed bytes exactly matches the expected payload length
	if processed != payloadLen {
		// This indicates data corruption or a flaw in nested DecodeRLP calls
		return nil, fmt.Errorf("%w: list payload processed %d bytes, expected %d", ErrInvalidRLPData, processed, payloadLen)
	}

	return items, nil
}

// bytesToUint64 converts a big-endian byte slice (max 8 bytes) representing a
// length or integer value to uint64.
// It performs canonical checks: no unnecessary leading zeros and the minimal number
// of bytes must be used for the value.
func bytesToUint64(b []byte) (uint64, error) {
	l := len(b)
	if l == 0 {
		// Empty bytes represents 0, which is valid for length encoding.
		return 0, nil
	}

	// Canonical check 1: Leading zero byte disallowed unless it's the only byte representing the value 0.
	// Since l > 0 here, a leading zero is always non-canonical for length prefixes.
	if b[0] == 0 {
		return 0, fmt.Errorf("%w: integer/length has leading zero", ErrNonCanonicalRLP)
	}

	// Check if length exceeds 8 bytes (max for uint64)
	if l > 8 {
		return 0, fmt.Errorf("%w: integer/length encoding longer than 8 bytes (%d)", ErrRLPIntegerTooLarge, l)
	}

	// Use binary.BigEndian.Uint64 on a padded 8-byte buffer
	var buf [8]byte
	copy(buf[8-l:], b) // Copy bytes to the end of the 8-byte buffer
	val := binary.BigEndian.Uint64(buf[:])

	// Canonical check 2: Check if the decoded value could have been encoded shorter.
	// This ensures that the length specified (l bytes) was minimal for the value.
	requiredBytes := 0
	if val > 0 {
		// Calculate the minimal number of bytes needed to represent val
		requiredBytes = (bits.Len64(val) + 7) / 8
	} // If val is 0, requiredBytes is 0, which is handled by l==0 case earlier.

	if requiredBytes < l {
		return 0, fmt.Errorf("%w: integer/length encoded with %d bytes, requires only %d", ErrNonCanonicalRLP, l, requiredBytes)
	}

	return val, nil
}
